    }
}

@page "/admin/users"
@attribute [Authorize(Roles = "Admin")]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@using sv_d1467b3e6302408bbd0374f434b6226f.Data

<PageTitle>User Administration</PageTitle>

<h1>User Administration</h1>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var u in users)
            {
                <tr>
                    <td>@u.FullName</td>
                    <td>@u.Email</td>
                    <td>@string.Join(", ", u.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? users;

    [Inject]
    private UserManager<ApplicationUser> UserManager { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        users = new List<UserWithRoles>();

        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            users.Add(new UserWithRoles
            {
                FullName = user.FullName,
                Email = user.Email ?? "",
                Roles = roles
            });
        }
    }

    private sealed class UserWithRoles
    {
        public string FullName { get; set; } = "";
        public string Email { get; set; } = "";
        public IList<string> Roles { get; set; } = [];
    }
}

@page "/directory"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@using sv_d1467b3e6302408bbd0374f434b6226f.Data

<PageTitle>Employee Directory</PageTitle>

<h1>Employee Directory</h1>
<p>This page is accessible to all authenticated users.</p>

@if (employees is null)
{
    <p><em>Loading directory...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var emp in employees)
            {
                <tr>
                    <td>@emp.FullName</td>
                    <td>@emp.Email</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ApplicationUser>? employees;

    [Inject]
    private UserManager<ApplicationUser> UserManager { get; set; } = default!;

    protected override void OnInitialized()
    {
        employees = UserManager.Users.OrderBy(u => u.FullName).ToList();
    }
}

