@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@using sv_d1467b3e6302408bbd0374f434b6226f.Data

<PageTitle>Employee Directory</PageTitle>

<h1>Employee Directory</h1>
<p>This page is accessible to all authenticated users.</p>

@if (employees is null)
{
    <p><em>Loading directory...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var emp in employees)
            {
                <tr>
                    <td>@emp.FullName</td>
                    <td>@emp.Email</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ApplicationUser>? employees;

    [Inject]
    private UserManager<ApplicationUser> UserManager { get; set; } = default!;

    protected override void OnInitialized()
    {
        employees = UserManager.Users.OrderBy(u => u.FullName).ToList();
    }
}

